295	// getResourceInfo returns descriptive information about a resource
296	func getResourceInfo(path string, entry os.DirEntry) string {
297		// Try to read description from README or description file
298		if entry.IsDir() {
299			readmePath := filepath.Join(path, "README.md")
300			if content, err := os.ReadFile(readmePath); err == nil {
301				lines := strings.Split(string(content), "\n")
302				for _, line := range lines {
303					line = strings.TrimSpace(line)
304					if line != "" && !strings.HasPrefix(line, "#") {
305						if len(line) > 60 {
306							return line[:60] + "..."
307						}
308						return line
309					}
310				}
311			}
312	
313			// Count items in directory
314			if entries, err := os.ReadDir(path); err == nil {
315				return fmt.Sprintf("%d items", len(entries))
316			}
317		} else {
318			// For files, show size or type
319			if stat, err := entry.Info(); err == nil {
320				ext := strings.ToLower(filepath.Ext(entry.Name()))
321				switch ext {
322				case ".md":
323					return "Markdown document"
324				case ".yml", ".yaml":
325					return "Configuration file"
326				case ".sh":
327					return "Shell script"
328				case ".py":
329					return "Python script"
330				case ".js":
331					return "JavaScript file"
332				case ".go":
333					return "Go source"
334				default:
335					if stat.Size() < 1024 {
336						return fmt.Sprintf("%d bytes", stat.Size())
337					} else if stat.Size() < 1024*1024 {
338						return fmt.Sprintf("%.1f KB", float64(stat.Size())/1024)
339					} else {
340						return fmt.Sprintf("%.1f MB", float64(stat.Size())/(1024*1024))
341					}
342				}
343			}
344		}
345	
346		return ""
347	}
