494	// buildTreeStructure builds a tree structure from flat resource list
495	func buildTreeStructure(resources []Resource) map[string]*TreeNode {
496		root := make(map[string]*TreeNode)
497	
498		for _, resource := range resources {
499			parts := strings.Split(resource.Name, "/")
500			current := root
501	
502			// Build path through tree
503			for i, part := range parts {
504				if current[part] == nil {
505					current[part] = &TreeNode{
506						Name:        part,
507						IsDirectory: i < len(parts)-1 || resource.IsDirectory,
508						Children:    make(map[string]*TreeNode),
509					}
510				}
511	
512				// If this is the last part, store the resource
513				if i == len(parts)-1 {
514					current[part].Resource = &resource
515				}
516	
517				current = current[part].Children
518			}
519		}
520	
521		return root
522	}
