527		var names []string
528		for name := range nodes {
529			names = append(names, name)
530		}
531		sort.Strings(names)
532	
533		for i, name := range names {
534			node := nodes[name]
535			isLast := i == len(names)-1
536	
537			// Choose tree characters
538			var connector, nextPrefix string
539			if isLast {
540				connector = "└── "
541				nextPrefix = prefix + "    "
542			} else {
543				connector = "├── "
544				nextPrefix = prefix + "│   "
545			}
546	
547			// Display node
